import{_ as a,o as e,c as p,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"《忍者杀手》远程武器系列","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/7.系列武器/《忍者杀手》远程武器系列.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/7.系列武器/《忍者杀手》远程武器系列.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/远程武器/7.系列武器/《忍者杀手》远程武器系列.md"};function _(o,b,d,l,i,c){return e(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"《忍者杀手》远程武器系列",tabindex:"-1"},[t("《忍者杀手》远程武器系列 "),r("a",{class:"header-anchor",href:"#《忍者杀手》远程武器系列","aria-label":'Permalink to "《忍者杀手》远程武器系列"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调012")])])],-1),n('<h1 id="《忍者杀手》远程武器系列-1" tabindex="-1">《忍者杀手》远程武器系列 <a class="header-anchor" href="#《忍者杀手》远程武器系列-1" aria-label="Permalink to &quot;《忍者杀手》远程武器系列&quot;">​</a></h1><p>《忍者杀手》远程武器系列</p><p>出自《忍者杀手》世界观，涵盖了大多数情况下的登场的标准远程武器。</p><p>chaka枪<br> 本质：科技本质<br> 价格：D+500<br> 描述：木芥子超市有卖的，最普遍和劣质的大量生产手枪。如果是两把一起的话也能成为以数量补充火力的现实选项。<br> 武器伤害：6L<br> 武器特性：【高速5】【长点射】<br> 弹容量：11+1<br> 射程：30<br> 定制槽：0<br> ●双靶：使用该武器攻击时，最多可以选择两个敌人作为目标，若选择同一目标，则改为对方在基础防御上承受2DP减值。</p><p>可差价升级至——<br> 定制·chaka枪<br> 价格：C+1000<br> 描述：能做到装备定制部件和稳定使用特殊弹药的高价Chaka枪，性能优秀。<br> 武器伤害：6L→11L<br> 定制槽：0→3<br> 武器特性：【高速6】【长点射→连射】<br> ●双靶：使用该武器攻击时，最多可以选择两个敌人作为目标，若选择同一目标，则改为对方在基础防御上承受2DP减值。<br> ●时间差：使用该武器攻击时，若对结果不满意，可以进行一次重骰（每轮一次，且结果必须接受）。</p><p>霰弹枪<br> 本质：科技本质<br> 价格：D+500<br> 描述：机动队、黑道、巨型企业佣兵等人常用的特种步枪。不仅是对人用的橡胶弹和散弹，也能射出对轻型载具用的独头弹。<br> 武器伤害：7L<br> 武器特性：【高速5】【长点射】【攻击距离不超过15米内的单位时获得2威猛】<br> 弹容量：11+1<br> 射程：40<br> 定制槽：2<br> ●抵近射击：每轮一次，你在攻击距离不超过15米内单位时，可选择将攻击动作提升至整轮动作（非标准动作则无法提升）。<br> 若本次攻击造成伤害，你对攻击目标进行一次冲撞，使用攻击成功数为结果对抗，并将本次造成严重伤害中的1点转为韧性伤害。</p><p>突击步枪<br> 本质：科技本质<br> 价格：D+500<br> 描述：湾岸警备队等使用的普通步兵用突击步枪。不仅是御村社、在天照·军火社和御名高岭社的产品也广为流通。泛用性好，也能装备简易的狙击用激光瞄准器部件等。<br> 武器伤害：7L<br> 武器特性：【高速5】【长点射】【特殊子弹器械减值-1】<br> 弹容量：30<br> 射程：150<br> 定制槽：2<br> ●点射3X3：可将攻击动作提升至整轮（非标准动作则无法提升），使本次攻击扇形覆盖射程一半（150/2=75）距离内的所有敌对单位，对每个敌人分别进行正常攻击检定。</p><p>守望·狙击枪<br> 本质：科技本质<br> 价格：D+500<br> 描述：理解区别所在的狙击手们，都会选择守望·光学社制的高性能狙击枪。<br> 武器伤害：8L<br> 武器特性：【高速5】【破甲3】【双手】<br> 弹容量：6+1<br> 射程：200<br> 定制槽：4<br> ●狙击：使用该武器攻击时减少3点部位减值。同时，视为已瞄准了一轮进行计算。</p><p>火焰放射器<br> 本质：科技本质<br> 价格：D+500<br> 描述：养老师·净化者等等最普通的火焰喷射器，用于驱逐危险BIO生物，在DIY家具城里也有贩卖。<br> 武器伤害：8L<br> 武器特性：【高速2】【破甲2】【双手】【短点射】<br> 弹容量：3+1<br> 射程：15<br> 定制槽：1<br> 伤害类型：火焰<br> ●焚烧重点：该武器造成伤害时，额外附带5点燃烧点数，标准豁免。</p><p>射击武器的定制配件一览<br> 插槽占用：该系列配件将占用对应定制槽，因此没有定制槽的武器无法使用定制配件。</p><p>弹药列表<br> 插槽占用：能使用弹药的，只有具有定制槽的枪械，但不消耗定制槽，除非注明例外，否则一种枪械只能装备一种弹药。</p><p>快拔·模块<br> 价格：500<br> 占用槽数：1<br> 对象枪械：手枪<br> 这个枪械在携带时，总是视为不占用重量与位置，也不会被安检等方式发现，这是一个无支线级的反侦测效果。<br> 这个枪械在战斗开始的第一轮进行攻击时，造成无支线措手不及影响。</p><p>红外线激光瞄准器<br> 价格：D+500<br> 占用槽数：1<br> 对象枪械：手枪、霰弹、步枪、狙击枪<br> 这个枪械在进行攻击检定时，获得可以减少【3】点DP，获得等量的附加成功。</p><p>点射·模块<br> 价格：D+500<br> 占用槽数：1<br> 对象枪械：手枪、狙击枪<br> 这个枪械获得●射击风格：点射3x3。<br> ●点射3X3：可将动作动作提升至整轮（非标准动作则无法提升），使本次攻击扇形覆盖射程一半距离内的所有敌对单位，对每个敌人分别进行正常攻击检定。</p><p>全弹发射·模块<br> 价格：C+2000<br> 占用槽数：2槽<br> 对象枪械：手枪、步枪<br> 这个枪械得获得●射击风格：子弹雨。<br> ●射击风格：子弹雨：攻击变更为反射检定豁免，而非正常防御流程。同时，使对方反射豁免DP获得你的传奇敏捷*2点减值。<br> 武器进行范围攻击的场合，可以选择敌我不分为代价，将范围射程提升1倍。</p><p>达人·长枪管<br> 价格：C+1000<br> 占用槽数：2槽<br> 对象枪械：狙击枪<br> 这个枪械进行不附带任何主动技艺的攻击时，获得4DP器械加值，以及1层【集中】。<br> 【集中】：攻击前进行一次额外的D10，若结果不大于【集中】层数，则这次攻击立刻增加一半伤害，并消耗1层【集中】。</p><p>电磁诱导枪管<br> 价格：C+1000<br> 占用槽数：2槽<br> 对象枪械：步枪、狙击枪<br> 这个枪械科技枪械化。以整轮动作使用该武器进行一次攻击（非标准则无法提升），获得【能量武器】【超级贯穿】【毁灭】特性。</p><p>刺刀·模块<br> 价格：C+1000<br> 占用槽数：安装了这个配件的武器定制槽+1<br> 对象枪械：步枪、霰弹、狙击枪<br> 安装在枪械上的高质量的刺刀，矛，小型电锯，或单纯用于殴打的枪管补强和握把强化。<br> 可选：以匕首或短棍为基础模板，具有轻灵特性，武器伤害提升8点，以安装的枪械武器技能+专业取代原有的技能+专业进行检定。</p><p>LAN直连模块<br> 价格：C+1000<br> 占用槽数：1槽<br> 对象枪械：任意<br> 直连型枪械无需用手指扣动物理板机，而是能够实现瞬间射击以Cyberne视觉锁定的对手。只要有活体LAN，无需进行射击训练，也可以以射击游戏般的感觉进行射击。<br> 这个枪械以智力属性代替原有的属性进行攻击，同时为枪械附加智力附加*5点高速。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',21)])])}const f=a(s,[["render",_]]);export{D as __pageData,f as default};
